import{_ as a,c as t,o as n,ag as i}from"./chunks/framework.Dj4VfQLU.js";const g=JSON.parse('{"title":"Currency & Language Configuration","description":"","frontmatter":{"icon":"earth-africa"},"headers":[],"relativePath":"currency-and-language-configuration.md","filePath":"currency-and-language-configuration.md"}'),s={name:"currency-and-language-configuration.md"};function r(o,e,l,d,c,p){return n(),t("div",null,e[0]||(e[0]=[i(`<h1 id="currency-language-configuration" tabindex="-1">Currency &amp; Language Configuration <a class="header-anchor" href="#currency-language-configuration" aria-label="Permalink to &quot;Currency &amp; Language Configuration&quot;">​</a></h1><p>BetterTaxi supports full <strong>multi-language</strong> and <strong>multi-currency</strong> capabilities. These settings determine how content and pricing are displayed across all interfaces — admin panel, driver app, customer app, and web panels.</p><hr><h3 id="🌐-language-localization" tabindex="-1">🌐 Language &amp; Localization <a class="header-anchor" href="#🌐-language-localization" aria-label="Permalink to &quot;🌐 Language &amp; Localization&quot;">​</a></h3><p>BetterTaxi includes <strong>32 languages</strong> out of the box. These are implemented using Flutter’s standard <code>.arb</code> format and the <code>flutter_localizations</code> package. Most are <strong>machine-translated</strong> and can be refined manually.</p><h4 id="🏗️-how-localization-works" tabindex="-1">🏗️ How Localization Works <a class="header-anchor" href="#🏗️-how-localization-works" aria-label="Permalink to &quot;🏗️ How Localization Works&quot;">​</a></h4><ul><li>Language files live in:<br><code>libs/flutter_localizations/lib/l10n/</code></li><li>Each <code>.arb</code> file corresponds to a locale (e.g. <code>en.arb</code>, <code>fr.arb</code>, <code>es.arb</code>)</li><li>Translations are auto-loaded in the app based on the device or user-selected language</li></ul><p><strong>🧪 To Customize a Translation:</strong></p><ol><li>Edit any <code>.arb</code> file to adjust strings</li><li>Maintain the key naming convention</li><li>Rebuild the localization files with:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flutter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gen-l10n</span></span></code></pre></div><p>This updates the Dart files used by the app’s localization runtime.</p><p><strong>🌍 Language Switching</strong></p><ul><li>Supported in all apps with built-in language selectors</li><li>Default language can be enforced using <code>.env</code> variables:</li></ul><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEFAULT_LANGUAGE=en</span></span>
<span class="line"><span>DEFAULT_LOCALE=en_US</span></span></code></pre></div><p>This is used as a fallback when user preference or system locale isn&#39;t detected.</p><hr><h3 id="💵-currency-system" tabindex="-1">💵 Currency System <a class="header-anchor" href="#💵-currency-system" aria-label="Permalink to &quot;💵 Currency System&quot;">​</a></h3><p>BetterTaxi uses a <strong>region-based currency model</strong>. This is managed through the Admin Panel and controlled by your operational zones.</p><h4 id="🧭-how-it-works" tabindex="-1">🧭 How It Works <a class="header-anchor" href="#🧭-how-it-works" aria-label="Permalink to &quot;🧭 How It Works&quot;">​</a></h4><ol><li><strong>Create a Region</strong> in the Admin Panel <ul><li>Go to <strong>Settings → Regions</strong></li><li>Define country, city, and operational area</li><li><strong>Assign a currency</strong> (e.g., USD, EUR, INR)</li></ul></li><li>Once assigned: <ul><li>That currency becomes the <strong>default for that region</strong></li><li>All <strong>fares, fees, payments, and receipts</strong> within that region will use the assigned currency</li><li>The same applies across <strong>mobile apps, web apps, and backend systems</strong></li></ul></li><li>You can create multiple regions, each with its own currency and zone-specific pricing.</li></ol><hr><h4 id="💱-currency-propagation" tabindex="-1">💱 Currency Propagation <a class="header-anchor" href="#💱-currency-propagation" aria-label="Permalink to &quot;💱 Currency Propagation&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Component</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>Customer App</strong></td><td>Displays prices in the region’s assigned currency</td></tr><tr><td><strong>Driver App</strong></td><td>Shows earnings, incentives, and trip values accordingly</td></tr><tr><td><strong>Admin Panel</strong></td><td>Reports, trip logs, and payment gateways adjust based on currency</td></tr><tr><td><strong>Payment Gateways</strong></td><td>Must support the assigned currency (configured per provider)</td></tr><tr><td><strong>SMS &amp; Receipts</strong></td><td>Show fare breakdowns in localized format</td></tr></tbody></table><p>Currency formatting (e.g., symbol placement, decimal precision) is handled automatically based on locale.</p><hr><h4 id="🌐-locale-measurement-settings" tabindex="-1">🌐 Locale &amp; Measurement Settings <a class="header-anchor" href="#🌐-locale-measurement-settings" aria-label="Permalink to &quot;🌐 Locale &amp; Measurement Settings&quot;">​</a></h4><p>Additional default settings can be defined via <code>.env</code>:</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEFAULT_COUNTRY=US</span></span>
<span class="line"><span>DEFAULT_CURRENCY=USD</span></span>
<span class="line"><span>DEFAULT_LANGUAGE=en</span></span>
<span class="line"><span>DEFAULT_LOCALE=en_US</span></span>
<span class="line"><span>METRIC_SYSTEM=metric       # or &#39;imperial&#39;</span></span>
<span class="line"><span>DEFAULT_LOCATION_LAT=40.7128</span></span>
<span class="line"><span>DEFAULT_LOCATION_LNG=-74.0060</span></span></code></pre></div><p>These affect:</p><ul><li>Distance units (e.g., miles vs. kilometers)</li><li>Currency formatting</li><li>Default coordinates when GPS is unavailable</li></ul><blockquote><p>📌 These values are used primarily during initial app launch and admin panel bootstrapping.</p></blockquote><hr><h4 id="📝-summary" tabindex="-1">📝 Summary <a class="header-anchor" href="#📝-summary" aria-label="Permalink to &quot;📝 Summary&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Feature</th><th>Configurable From</th><th>Format / Tool</th></tr></thead><tbody><tr><td>Default Language</td><td><code>.env</code> file</td><td><code>DEFAULT_LANGUAGE</code></td></tr><tr><td>Translations</td><td><code>libs/flutter_localizations</code></td><td><code>.arb</code> + <code>flutter gen-l10n</code></td></tr><tr><td>Default Currency</td><td>Admin Panel → Region</td><td>Set per region</td></tr><tr><td>Metric System</td><td><code>.env</code> file</td><td>\`METRIC_SYSTEM=metric</td></tr><tr><td>Default Location</td><td><code>.env</code> file</td><td><code>DEFAULT_LOCATION_LAT/LNG</code></td></tr></tbody></table>`,34)]))}const h=a(s,[["render",r]]);export{g as __pageData,h as default};
